                     new(ReporterType.Json),
                     new(ReporterType.Markdown),
                 };

             var judgeMode = parseResult.GetValue(judgeModeOpt) switch
             {
                 "independent" => JudgeMode.Independent,
                 "both" => JudgeMode.Both,
                 _ => JudgeMode.Pairwise,
             };

             var config = new ValidatorConfig
             {
