1. namespace SkillValidator.Evaluate;
2. 
3. public static class EvalSchema
4. {
5.     /// <summary>Default scenario timeout in seconds when not specified in eval.yaml.</summary>
6.     public const int DefaultScenarioTimeoutSeconds = 120;
7. 
8.     public static EvalConfig ParseEvalConfig(string yamlContent)
9.     {
10.         var raw = SkillValidatorYamlContext.UnderscoredDeserializer.Deserialize<RawEvalConfig>(yamlContent)
11.             ?? throw new InvalidOperationException("Failed to parse eval config YAML");
12. 
13.         var scenarios = raw.Scenarios?.Select(ParseScenario).ToList();
14. 
15.         if (scenarios is not { Count: > 0 })
16.             throw new InvalidOperationException("Eval config must have at least one scenario");
17. 
18.         return new EvalConfig(
19.             scenarios,
20.             MaxParallelScenarios: raw.Config?.MaxParallelScenarios,
21.             MaxParallelRuns: raw.Config?.MaxParallelRuns);
22.     }
23. 
24.     public static (bool Success, EvalConfig? Data, IReadOnlyList<string>? Errors) ValidateEvalConfig(string yamlContent)
25.     {
26.         try
27.         {
28.             var config = ParseEvalConfig(yamlContent);
29.             return (true, config, null);
30.         }
31.         catch (Exception ex)
32.         {
33.             return (false, null, [ex.Message]);
34.         }
35.     }
36. 
37.     private static EvalScenario ParseScenario(RawScenario raw)
38.     {
39.         if (string.IsNullOrWhiteSpace(raw.Name))
40.             throw new InvalidOperationException("Scenario name is required");
41.         if (string.IsNullOrWhiteSpace(raw.Prompt))
42.             throw new InvalidOperationException("Scenario prompt is required");
43. 
44.         var assertions = raw.Assertions?.Select(ParseAssertion).ToList();
45. 
46.         SetupConfig? setup = null;
47.         if (raw.Setup is not null)
48.         {
49.             var files = raw.Setup.Files?.Select(f =>
50.                 new SetupFile(f.Path, f.Source, f.Content)).ToList();
51.             setup = new SetupConfig(
52.                 raw.Setup.CopyTestFiles,
53.                 files,
54.                 raw.Setup.Commands,
55.                 raw.Setup.AdditionalRequiredSkills,
56.                 raw.Setup.AdditionalRequiredAgents);
57.         }
58. 
59.         return new EvalScenario(
60.             Name: raw.Name,
61.             Prompt: raw.Prompt,
62.             Setup: setup,
63.             Assertions: assertions,
64.             Rubric: raw.Rubric,
65.             Timeout: raw.Timeout ?? DefaultScenarioTimeoutSeconds,
66.             ExpectTools: raw.ExpectTools,
67.             RejectTools: raw.RejectTools,
68.             MaxTurns: raw.MaxTurns,
69.             MaxTokens: raw.MaxTokens,
70.             ExpectActivation: raw.ExpectActivation ?? true);
71.     }
72. 
73.     private static Assertion ParseAssertion(RawAssertion raw)
74.     {
75.         var type = raw.Type switch
76.         {
77.             "file_exists" => AssertionType.FileExists,
78.             "file_not_exists" => AssertionType.FileNotExists,
79.             "file_contains" => AssertionType.FileContains,
80.             "file_not_contains" => AssertionType.FileNotContains,
81.             "output_contains" => AssertionType.OutputContains,
82.             "output_not_contains" => AssertionType.OutputNotContains,
83.             "output_matches" => AssertionType.OutputMatches,
84.             "output_not_matches" => AssertionType.OutputNotMatches,
85.             "exit_success" => AssertionType.ExitSuccess,
86.             "run_command_and_assert" => AssertionType.RunCommandAndAssert,
87.             _ => throw new InvalidOperationException($"Unknown assertion type: {raw.Type}"),
88.         };
89. 
90.         // Validate required fields per assertion type
91.         switch (type)
92.         {
93.             case AssertionType.FileExists or AssertionType.FileNotExists:
94.                 if (string.IsNullOrWhiteSpace(raw.Path))
95.                     throw new InvalidOperationException($"Assertion '{raw.Type}' requires 'path'");
96.                 break;
97.             case AssertionType.FileContains or AssertionType.FileNotContains:
98.                 if (string.IsNullOrWhiteSpace(raw.Path))
99.                     throw new InvalidOperationException($"Assertion '{raw.Type}' requires 'path'");
100.                 if (string.IsNullOrWhiteSpace(raw.Value))
101.                     throw new InvalidOperationException($"Assertion '{raw.Type}' requires 'value'");
102.                 break;
103.             case AssertionType.OutputContains or AssertionType.OutputNotContains:
104.                 if (string.IsNullOrWhiteSpace(raw.Value))
105.                     throw new InvalidOperationException($"Assertion '{raw.Type}' requires 'value'");
106.                 break;
107.             case AssertionType.OutputMatches or AssertionType.OutputNotMatches:
108.                 if (string.IsNullOrWhiteSpace(raw.Pattern))
109.                     throw new InvalidOperationException($"Assertion '{raw.Type}' requires 'pattern'");
110.                 break;
111.             case AssertionType.RunCommandAndAssert:
112.                 if (string.IsNullOrWhiteSpace(raw.CommandToRun))
113.                     throw new InvalidOperationException($"Assertion '{raw.Type}' requires 'command_to_run'");
114. 
115.                 if (raw.ExpectedExitCode is null &&
116.                     string.IsNullOrWhiteSpace(raw.ExpectedStdOutputContains) &&
117.                     string.IsNullOrWhiteSpace(raw.ExpectedStdErrorContains) &&
118.                     string.IsNullOrWhiteSpace(raw.ExpectedStdOutputMatches) &&
119.                     string.IsNullOrWhiteSpace(raw.ExpectedStdErrorMatches))
120.                     throw new InvalidOperationException($"Assertion '{raw.Type}' requires one or more of 'expected_exit_code', 'expected_std_output_contains', 'expected_std_error_contains', 'expected_std_output_matches', or 'expected_std_error_matches'");
121.                 break;
122.         }
123. 
124.         CommandAssertionArgs? commandArgs = type == AssertionType.RunCommandAndAssert
125.             ? new CommandAssertionArgs(
126.                 raw.CommandToRun!,
127.                 NullIfWhiteSpace(raw.CommandArguments),
128.                 raw.ExpectedExitCode,
129.                 NullIfWhiteSpace(raw.ExpectedStdOutputContains),
130.                 NullIfWhiteSpace(raw.ExpectedStdErrorContains),
131.                 NullIfWhiteSpace(raw.ExpectedStdOutputMatches),
132.                 NullIfWhiteSpace(raw.ExpectedStdErrorMatches),
133.                 raw.CommandTimeout)
134.             : null;
135. 
136.         return new Assertion(type, raw.Path, raw.Value, raw.Pattern, commandArgs);
137.     }
138. 
139.     private static string? NullIfWhiteSpace(string? value) =>
140.         string.IsNullOrWhiteSpace(value) ? null : value;
141. 
142.     // Raw YAML deserialization models
143. 
144.     internal sealed class RawEvalConfig
